import React, { useCallback, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Select,
  SearchTextInput,
  StatusBadge,
  dispatchAppToast,
  LIN_ERP_LIST_FILTER_LAYOUT,
  LinErpListFilterBar,
  LinPageLayout,
  LinListTableConfigModal,
  loadErpListTableConfig,
  saveErpListTableConfig,
  useViewMobileLayout,
  useErpListSelection,
  useCatalogTableBusy,
  type ErpListTableConfig,
  LabelMoney,
  formatUTCToLocalDisplay,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../store/hooks';
import { bhService } from '../../services/bh/bhService';
import type { ContractDto } from '../../services/bh/models';
import { getApiErrorMessage } from '../../utils/getApiErrorMessage';
import {
  VOUCHER_LIST_ROW_MENU_HINT_DESKTOP,
  VOUCHER_LIST_ROW_MENU_HINT_TOUCH,
} from '../../utils/voucherListRowMenuHint';
import { useVoucherListActions } from '../../hooks/useVoucherListActions';
import { VoucherRowActionMenu, type VoucherRowMenuAction } from '../voucher-list/VoucherRowActionMenu';
import { CatalogDocumentHistory } from '../catalog/CatalogDocumentHistory';
import { salesDocumentTypes } from '../../config/documentHistoryClients';
import {
  DEFAULT_PAGE_SIZE,
  VoucherListPagination,
  type ListPageSize,
} from '../list/VoucherListPagination';
import erp from '../../styles/erpPage.module.css';

const TEST_ID = 'bh-hop-dong';
const PAGE_ID = 'bh-hop-dong';
const CREATE_FORM = 'create-sales-contract';

const STATUS_OPTIONS = [
  { value: '', label: 'Tất cả' },
  { value: 'Draft', label: 'Nháp' },
  { value: 'Active', label: 'Hiệu lực' },
  { value: 'Closed', label: 'Đã đóng' },
  { value: 'Cancelled', label: 'Đã hủy' },
];

const LIST_COLUMNS = [
  { id: 'code', label: 'Số HĐ' },
  { id: 'contractDate', label: 'Ngày' },
  { id: 'customerName', label: 'Khách hàng' },
  { id: 'totalAmount', label: 'Giá trị' },
  { id: 'status', label: 'Trạng thái' },
] as const;

function filterBySearch(rows: ContractDto[], search: string): ContractDto[] {
  const q = search.trim().toLowerCase();
  if (!q) return rows;
  return rows.filter(
    r =>
      r.code.toLowerCase().includes(q) ||
      (r.customerName ?? '').toLowerCase().includes(q) ||
      (r.description ?? '').toLowerCase().includes(q),
  );
}

export const HopDongList: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const viewMobile = useViewMobileLayout();
  const { canCreate, canUpdate } = useVoucherListActions(CREATE_FORM);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [status, setStatus] = useState('');
  const [page, setPage] = useState(1);
  const [pageSize, setPageSizeState] = useState<ListPageSize>(DEFAULT_PAGE_SIZE);
  const [items, setItems] = useState<ContractDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [showConfigModal, setShowConfigModal] = useState(false);
  const [historyOpen, setHistoryOpen] = useState(false);
  const [tableConfig, setTableConfig] = useState<ErpListTableConfig>(() =>
    loadErpListTableConfig(TEST_ID),
  );
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: ContractDto } | null>(null);
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const selection = useErpListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: () => false,
  });

  const activeRow = selection.activeRow;

  const refresh = useCallback(() => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  }, [selection]);

  const navigateToEdit = useCallback(
    (contractId: string) => {
      navigate(`/bh/hd/${contractId}/sua`);
    },
    [navigate],
  );

  const navigateToRow = useCallback(
    (id: string) => {
      navigate(`/bh/hd/${id}`);
    },
    [navigate],
  );

  const handleSearch = useCallback(() => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      setPage(1);
      selection.clearSelection();
      setReloadKey(k => k + 1);
    });
  }, [pulseSearch, searchDraft, selection]);

  const setPageSize = (size: number) => {
    setPageSizeState(size as ListPageSize);
    setPage(1);
    selection.clearSelection();
  };

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      bhService
        .getContracts({
          status: status || undefined,
          page,
          pageSize,
        })
        .then(res => {
          if (cancelled) return;
          const filtered = filterBySearch(res.items, search);
          setItems(filtered);
          setTotalCount(search.trim() ? filtered.length : res.totalCount);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, 'Lỗi tải danh sách hợp đồng'),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [status, page, pageSize, search, reloadKey, dispatch]);

  const handleSaveTableConfig = (config: ErpListTableConfig) => {
    setTableConfig(config);
    saveErpListTableConfig(TEST_ID, config);
    setShowConfigModal(false);
  };

  const rowMenuHintMessage = viewMobile
    ? VOUCHER_LIST_ROW_MENU_HINT_TOUCH
    : VOUCHER_LIST_ROW_MENU_HINT_DESKTOP;

  const handleRowOpenActionMenu = useCallback(
    ({ row, x, y }: { row: ContractDto; x: number; y: number }) => {
      selection.selectActiveRow(row);
      setRowMenu({ x, y, row });
    },
    [selection],
  );

  const handleRowMenuSelect = useCallback(
    (action: VoucherRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      if (action === 'view') navigateToRow(row.id);
      if (action === 'edit' && canUpdate) navigateToEdit(row.id);
    },
    [rowMenu?.row, canUpdate, navigateToRow, navigateToEdit],
  );

  const renderCell = (row: ContractDto, colId: string) => {
    switch (colId) {
      case 'code':
        return (
          <button
            type="button"
            className={erp.codeLink}
            onClick={() => navigateToRow(row.id)}
            data-testid={`${TEST_ID}-row-${row.id}-code`}
          >
            <code>{row.code}</code>
          </button>
        );
      case 'contractDate':
        return formatUTCToLocalDisplay(row.contractDate, false);
      case 'customerName':
        return row.customerName;
      case 'totalAmount':
        return <span className={erp.colRight}><LabelMoney layout="value" variant="cell" value={row.totalAmount} /></span>;
      case 'status':
        return <StatusBadge status={row.status} />;
      default:
        return null;
    }
  };

  const catalogToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: refresh,
      canAdd: canCreate,
      onAdd: () => navigate('/bh/hd/them'),
      canHistory: !!activeRow,
      onHistory: () => activeRow && setHistoryOpen(true),
      showView: true,
      onView: () => activeRow && navigateToRow(activeRow.id),
      showEdit: canUpdate,
      onEdit: () => activeRow && canUpdate && navigateToEdit(activeRow.id),
      onEditConfig: () => setShowConfigModal(true),
      showSchemaConfig: true,
    }),
    [refresh, activeRow, canCreate, canUpdate, navigate, navigateToRow, navigateToEdit],
  );

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        onDateChange={() => {}}
        onSearch={handleSearch}
        loading={showTableLoading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-search`}>
              <SearchTextInput
                label="Tìm kiếm"
                placeholder="Tìm số HĐ, khách hàng, diễn giải..."
                value={searchDraft}
                onChange={setSearchDraft}
                onSearch={handleSearch}
                testId={`${TEST_ID}-search-text`}
              />
            </div>
            <div data-testid={`${TEST_ID}-field-status`}>
              <Select
                label="Trạng thái"
                value={status}
                onChange={e => {
                  setStatus(e.target.value);
                  setPage(1);
                  selection.clearSelection();
                }}
                options={STATUS_OPTIONS}
                data-testid={`${TEST_ID}-status`}
              />
            </div>
          </>
        )}
      />
    ),
    [searchDraft, status, handleSearch, selection, showTableLoading],
  );

  const listBody =
    !showTableLoading && items.length === 0 ? (
      <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
        <p>Không có hợp đồng</p>
      </div>
    ) : !showTableLoading ? (
      <div className={erp.tableWrapper} data-testid={`${TEST_ID}-table-wrapper`}>
        <table className={erp.table} data-testid={`${TEST_ID}-table`}>
          <thead>
            <tr>
              {LIST_COLUMNS.map(col => (
                <th key={col.id}>{col.label}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {items.map(row => {
              const isActive = selection.isRowActive(row);
              return (
                <tr
                  key={row.id}
                  className={isActive ? erp.catalogRowActive : ''}
                  onClick={() => selection.selectActiveRow(row)}
                  onContextMenu={e => {
                    e.preventDefault();
                    handleRowOpenActionMenu({ row, x: e.clientX, y: e.clientY });
                  }}
                  data-testid={`${TEST_ID}-row-${row.id}`}
                >
                  {LIST_COLUMNS.map(col => (
                    <td key={col.id}>{renderCell(row, col.id)}</td>
                  ))}
                </tr>
              );
            })}
          </tbody>
        </table>
        <p className={erp.rowMenuHint} data-testid={`${TEST_ID}-row-menu-hint`}>
          {rowMenuHintMessage}
        </p>
      </div>
    ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="catalog"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: 'Hợp đồng bán',
          titleIconClass: 'fas fa-file-contract',
          pageId: PAGE_ID,
        }}
        catalogToolbar={catalogToolbar}
        listTitle="Danh sách hợp đồng"
        listRowMenuHelp
        filters={listFilters}
        listLayoutVariant="erp-filter-bar"
        listHeaderClassName={LIN_ERP_LIST_FILTER_LAYOUT.header}
        listFiltersClassName={LIN_ERP_LIST_FILTER_LAYOUT.filtersHost}
        showTableLoading={showTableLoading}
        skeletonRows={Math.min(pageSize, 8)}
        footer={
          <VoucherListPagination
            testIdPrefix={TEST_ID}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => {
              setPage(p);
              selection.clearSelection();
            }}
            onPageSizeChange={setPageSize}
          />
        }
        modals={
          <>
            <LinListTableConfigModal
              isOpen={showConfigModal}
              onClose={() => setShowConfigModal(false)}
              testIdPrefix={TEST_ID}
              config={tableConfig}
              onSave={handleSaveTableConfig}
            />
            <VoucherRowActionMenu
              open={rowMenu != null}
              x={rowMenu?.x ?? 0}
              y={rowMenu?.y ?? 0}
              onClose={() => setRowMenu(null)}
              onSelect={handleRowMenuSelect}
              testIdPrefix={TEST_ID}
              showView
              showEdit={canUpdate}
              showViewLedger={false}
              showPrint={false}
            />
            <CatalogDocumentHistory
              testIdPrefix={TEST_ID}
              documentType={salesDocumentTypes.salesContract}
              documentId={activeRow?.id}
              documentCode={activeRow?.code}
              isOpen={historyOpen}
              onClose={() => setHistoryOpen(false)}
            />
          </>
        }
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default HopDongList;
